use crate::codec::tss::decode_tss_message;

pub fn verify_message(prices: &[(String, u64)], tss_message: &[u8]) -> Result<(), anyhow::Error> {
    let tss_message = decode_tss_message(tss_message)?;

    let signal_prices = tss_message.signal_prices()?;

    if prices != signal_prices {
        return Err(anyhow::anyhow!(
            "Prices do not match: tx_signal_prices={:?}, tss_signal_prices={:?}",
            prices,
            signal_prices
        ));
    }
    Ok(())
}

#[cfg(test)]
mod integration_tests {
    use super::*;
    use hex::decode;

    #[test]
    fn test_verify_message_xrpl_vs_tss() {
        // Prices
        let prices = vec![
            ("CS:BTC-USD".into(), 70739198202079_u64),
            ("CS:ETH-USD".into(), 2085436925307_u64),
            ("CS:RLUSD-USD".into(), 999843425_u64),
            ("CS:USDC-USD".into(), 999800000_u64),
            ("CS:USDT-USD".into(), 999376674_u64),
            ("CS:WBTC-USD".into(), 70524704190393_u64),
            ("CS:XRP-USD".into(), 1439825578_u64),
        ];

        // TSS Message (Hex)
        let tss_message_hex = ""; // Note: Fixed potential truncated hex in example
        let tss_msg_bytes = decode(tss_message_hex).expect("Invalid TSS hex");

        let result = verify_message(prices.as_slice(), &tss_msg_bytes);

        // Assertions
        assert!(result.is_ok());
    }
}
